// Sample incoming HRIS payload (replace with your actual field mapping)
const raw = $input.first().json;

// ── SAMPLE NEW HIRE DATA ──────────────────────────────────────────────
// Name:       Jordan Riley
// Email:      j.riley@company.com
// Dept:       Engineering
// Role:       Backend Engineer
// Manager:    sarah.kim@company.com
// Start Date: 2026-03-16
// Location:   Remote - US West
// Risk Level: standard
// ─────────────────────────────────────────────────────────────────────

const newHire = {
  firstName:   raw.firstName    || 'Jordan',
  lastName:    raw.lastName     || 'Riley',
  email:       raw.email        || 'j.riley@company.com',
  department:  raw.department   || 'Engineering',
  role:        raw.jobTitle     || 'Backend Engineer',
  manager:     raw.managerEmail || 'sarah.kim@company.com',
  startDate:   raw.startDate    || '2026-03-16',
  location:    raw.location     || 'Remote - US West',
  employeeId:  raw.employeeId   || 'EMP-20241',
  riskLevel:   raw.riskLevel    || 'standard',   // standard | elevated | high
  cloudProfile: {
    primaryCloud:   'aws',
    defaultGroups:  ['eng-general', 'eng-backend'],
    costCenter:     'ENG-001'
  }
};

return [{ json: { newHire } }];

const response = $input.first().json;

let plan;
try {
  // OpenCode returns the plan inside response.result or response.content
  const raw = response.result || response.content || response;
  plan = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  return [{ json: { valid: false, error: 'Failed to parse AI plan: ' + e.message, raw: response } }];
}

const hasOkta  = Array.isArray(plan.oktaActions);
const hasEntra = Array.isArray(plan.entraActions);
const hasCloud = Array.isArray(plan.cloudActions);

if (!hasOkta || !hasEntra) {
  return [{ json: { valid: false, error: 'Missing required arrays in plan', plan } }];
}

return [{ json: { valid: true, plan } }];

